import axios from 'axios';

// Create a reusable axios instance with defaults
const apiClient = axios.create({
  baseURL: process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api',
  timeout: 10000,  // 10 second timeout
  headers: {
    'Content-Type': 'application/json',
  },
});

// --- Interceptors ---
// Interceptors run automatically on every request or response.
// Think of them as middleware for your API calls.

// Request interceptor: runs BEFORE every request is sent
apiClient.interceptors.request.use((config) => {
  // Example: attach an auth token if it exists
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// Response interceptor: runs AFTER every response arrives
apiClient.interceptors.response.use(
  (response) => response,  // success: just pass it through
  (error) => {
    // Error: log it and show a user-friendly message
    if (error.response?.status === 401) {
      console.error('Session expired. Please log in again.');
    }
    return Promise.reject(error);
  }
);

export default apiClient;

import apiClient from './client';
import { Question } from '@/types/question';

// Fetch all questions (or questions filtered by topic)
export async function getQuestions(topicSlug?: string): Promise<Question[]> {
  try {
    const params = topicSlug ? { topic: topicSlug } : {};
    const response = await apiClient.get<Question[]>('/questions', { params });
    return response.data;
  } catch (error) {
    console.error('Failed to fetch questions:', error);
    throw error;  // let the component decide how to handle it
  }
}

// Fetch a single question by ID
export async function getQuestionById(id: string): Promise<Question> {
  try {
    const response = await apiClient.get<Question>(`/questions/${id}`);
    return response.data;
  } catch (error) {
    console.error(`Failed to fetch question ${id}:`, error);
    throw error;
  }
}

import { useState, useEffect } from 'react';
import { getQuestions } from '@/api/questions';
import { Question } from '@/types/question';

function QuizPage({ topicSlug }: { topicSlug: string }) {
  const [questions, setQuestions] = useState<Question[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function loadQuestions() {
      try {
        setLoading(true);
        setError(null);
        const data = await getQuestions(topicSlug);
        setQuestions(data);
      } catch (err) {
        setError('Could not load questions. Please try again.');
      } finally {
        setLoading(false);  // runs whether it succeeded or failed
      }
    }

    loadQuestions();
  }, [topicSlug]);

  if (loading) return <CircularProgress />;
  if (error) return <Alert severity="error">{error}</Alert>;
  if (questions.length === 0) return <Typography>No questions found.</Typography>;

  return (
    <div>
      {questions.map((q) => (
        <QuestionCard key={q.id} question={q} />
      ))}
    </div>
  );
}

