  return data;
}

import { createSlice, createAsyncThunk } from '@reduxjs/toolkit';
import { getQuestions } from '@/api/questions';
import { Question } from '@/types/question';

interface QuizState {
  questions: Question[];
  currentIndex: number;
  loading: boolean;
  error: string | null;
}

const initialState: QuizState = {
  questions: [],
  currentIndex: 0,
  loading: false,
  error: null,
};

// Async thunk: fetches questions and puts them in Redux
export const fetchQuestions = createAsyncThunk(
  'quiz/fetchQuestions',
  async (topicSlug: string) => {
    const questions = await getQuestions(topicSlug);
    return questions;
  }
);

const quizSlice = createSlice({
  name: 'quiz',
  initialState,
  reducers: {
    nextQuestion(state) {
      if (state.currentIndex < state.questions.length - 1) {
        state.currentIndex += 1;
      }
    },
    resetQuiz(state) {
      state.currentIndex = 0;
    },
  },
  extraReducers: (builder) => {
    builder
      .addCase(fetchQuestions.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchQuestions.fulfilled, (state, action) => {
        state.loading = false;
        state.questions = action.payload;
        state.currentIndex = 0;
      })
      .addCase(fetchQuestions.rejected, (state, action) => {
        state.loading = false;
        state.error = action.error.message || 'Failed to load questions';
      });
  },
});

export const { nextQuestion, resetQuiz } = quizSlice.actions;
export default quizSlice.reducer;

