'use client';

import { useEffect } from 'react';
import { useAppDispatch, useAppSelector } from '@/store/hooks';
import { fetchQuestions, nextQuestion } from '@/store/slices/quizSlice';
import QuestionCard from '@/components/QuestionCard';
import CircularProgress from '@mui/material/CircularProgress';
import Alert from '@mui/material/Alert';

export default function QuizPage() {
  const dispatch = useAppDispatch();
  const { questions, currentIndex, loading, error } = useAppSelector(
    (state) => state.quiz
  );

  useEffect(() => {
    dispatch(fetchQuestions('basics'));
  }, [dispatch]);

  if (loading) return <CircularProgress />;
  if (error) return <Alert severity="error">{error}</Alert>;
  if (questions.length === 0) return <p>No questions available.</p>;

  const currentQuestion = questions[currentIndex];

  const handleAnswer = (questionId: string, selectedLabel: string) => {
    console.log(`Answered ${questionId}: ${selectedLabel}`);
    dispatch(nextQuestion());
  };

  return (
    <div>
      <p>Question {currentIndex + 1} of {questions.length}</p>
      <QuestionCard
        question={currentQuestion}
        onAnswer={handleAnswer}
      />
    </div>
  );
}

